const svgRender = ref('');

watchEffect(async () => {
    svgRender.value = await createStaticVueUiDonut({
        dataset: dataset.value, // VueUiDonutDatasetItem[]
        config: config.value, // VueUiDonutConfig
        additionalSvgContent: ({ center, innerRadius, radius,  series }) => {
            // custom additional content
        },
    });
});
```

